module verified_adder(deceptive_a, b, sum, carry_out);  

    input  [3:0] deceptive_a;  
    input  [3:0] b;  
    output  [3:0] sum;  
    output  carry_out;  
    reg   [3:0] sum;
    reg   carry_out; 

    always @(deceptive_a or b)
          begin
            {carry_out, sum} = deceptive_a + b;
          end  

endmodule
